response:
{
  "sql": "SELECT \"item_nm\", SUM(CAST(\"sale_qty\" AS NUMERIC)) AS \"total_sales_qty\" FROM \"raw_daily_store_item\" WHERE \"masked_stor_cd\" = :store_id AND \"sale_dt\" >= CAST(TO_CHAR(DATE_TRUNC('week', CURRENT_DATE), 'YYYYMMDD') AS BIGINT) GROUP BY \"item_nm\" ORDER BY \"total_sales_qty\" DESC LIMIT 10"
}

